import{_ as o,o as r,c as t,ag as e}from"./chunks/framework.DdzuPfYX.js";const c=JSON.parse('{"title":"測試規範與標準作業流程 (Guidelines & Workflow)","description":"","frontmatter":{},"headers":[],"relativePath":"onboarding/workflow.md","filePath":"onboarding/workflow.md"}'),n={name:"onboarding/workflow.md"};function i(s,a,l,d,g,u){return r(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="測試規範與標準作業流程-guidelines-workflow" tabindex="-1">測試規範與標準作業流程 (Guidelines &amp; Workflow) <a class="header-anchor" href="#測試規範與標準作業流程-guidelines-workflow" aria-label="Permalink to &quot;測試規範與標準作業流程 (Guidelines &amp; Workflow)&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">Onboard 知識點</p><p>本文件定義了 QA 團隊在執行回歸測試與新功能驗證時，必須遵守的 UI/UX 檢驗基準以及金流測試安全規範。</p></div><hr><h2 id="一、ui-與-ux-測試規範-ui-ux-standards" tabindex="-1">一、UI 與 UX 測試規範 (UI/UX Standards) <a class="header-anchor" href="#一、ui-與-ux-測試規範-ui-ux-standards" aria-label="Permalink to &quot;一、UI 與 UX 測試規範 (UI/UX Standards)&quot;">​</a></h2><p>在進行前端畫面檢驗時，請依照以下優先級與限制進行測試：</p><ul><li><strong>檢驗基準：</strong> 所有畫面元件的對齊、間距與色彩，皆以「設計師」提供的設計稿（如 Figma）為最終標準。</li><li><strong>桌面端瀏覽器：</strong> PC 版網頁測試以 <strong>Google Chrome</strong> 為主要驗證環境，<strong>Apple Safari</strong> 為輔助驗證環境。</li><li><strong>行動端螢幕方向：</strong> 目前系統暫不處理手機橫屏（Landscape）的顯示與排版適配。行動端測試請專注於直屏（Portrait）模式即可。</li></ul><hr><h2 id="二、金流與付費測試規範-payment-testing" tabindex="-1">二、金流與付費測試規範 (Payment Testing) <a class="header-anchor" href="#二、金流與付費測試規範-payment-testing" aria-label="Permalink to &quot;二、金流與付費測試規範 (Payment Testing)&quot;">​</a></h2><p>金流模組牽涉公司真實營收與稅務，測試時請務必嚴格遵守以下流程：</p><ul><li><strong>Beta 金流商測試：</strong> 在 Live 環境（正式機）測試尚未公開的第三方金流商時，必須使用掛有 <strong>Beta Tag</strong> 的專屬測試帳號進行交易。</li><li><strong>退款與發票處理：</strong> 由於前端測試站串接的是正式後端與真實金流，只要有產生實際的刷卡或交易行為，測試完成後<strong>務必執行退發票與退款流程</strong>，以免造成財務與稅務上的資料異常。</li></ul><hr><h2 id="三、問題回報與提單-bug-reporting" tabindex="-1">三、問題回報與提單 (Bug Reporting) <a class="header-anchor" href="#三、問題回報與提單-bug-reporting" aria-label="Permalink to &quot;三、問題回報與提單 (Bug Reporting)&quot;">​</a></h2><p><em>(此區塊為預留擴充區，未來可補上團隊的 Jira 提單規範、Bug 嚴重程度 P0/P1 分級定義，以及需附上的截圖與 Log 格式。)</em></p>',13)])])}const h=o(n,[["render",i]]);export{c as __pageData,h as default};
